setup.query:
#graphql
  mutation GiftCardUpdateClearNullableCreate($input: GiftCardCreateInput!) {
    giftCardCreate(input: $input) {
      giftCard {
        id
        note
        expiresOn
        templateSuffix
      }
      giftCardCode
      userErrors {
        field
        message
      }
    }
  }

clear.query:
#graphql
  mutation GiftCardUpdateClearNullable($id: ID!) {
    noteClear: giftCardUpdate(id: $id, input: { note: null }) {
      giftCard {
        id
        note
        expiresOn
        templateSuffix
        updatedAt
      }
      userErrors {
        field
        message
      }
    }
    expiresClear: giftCardUpdate(id: $id, input: { expiresOn: null }) {
      giftCard {
        id
        note
        expiresOn
        templateSuffix
        updatedAt
      }
      userErrors {
        field
        message
      }
    }
    templateClear: giftCardUpdate(id: $id, input: { templateSuffix: null }) {
      giftCard {
        id
        note
        expiresOn
        templateSuffix
        updatedAt
      }
      userErrors {
        field
        message
      }
    }
  }

readAfterClear.query:
#graphql
  query GiftCardUpdateClearNullableRead($id: ID!) {
    giftCard(id: $id) {
      id
      note
      expiresOn
      templateSuffix
      updatedAt
    }
  }

cleanup.query:
#graphql
      mutation GiftCardUpdateClearNullableGiftCardDeactivate($id: ID!) {
        giftCardDeactivate(id: $id) {
          giftCard {
            id
            enabled
            deactivatedAt
          }
          userErrors {
            field
            message
          }
        }
      }
